mapper.select:
SELECT e.id, e.username, e.password, e.name, e.gender, e.phone, e.dept_id, e.entry_date, e.create_time, e.update_time, d.name AS deptName FROM emp e LEFT JOIN dept d ON e.dept_id = d.id
AND e.name LIKE CONCAT('%', #{name}, '%')
AND e.gender = #{gender}
AND e.dept_id = #{deptId}
AND DATE(e.entry_date) >= #{begin}
AND DATE(e.entry_date) <= #{end}
ORDER BY e.update_time DESC

mapper.update:
update emp
username = #{username}, password = #{password}, name = #{name}, gender = #{gender}, phone = #{phone}, salary = #{salary}, image = #{image}, entry_date = #{entryDate}, dept_id = #{deptId}, update_time = #{updateTime},
where id = #{id}
